ENFR=function(en,tries){
	if(!tries||!In(Keys(EnglishFrench),en))
		return en;

	var fr=EnglishFrench[en];
	if(!IsArray(fr))
		fr=[fr];

	fr=fr.map(x=>(Prefixed(x,"*")?ENFR(x,tries-1):[x]));
	fr=fr.reduce((x,y)=>x.concat(y));
	return Unique(fr);
}

